        SAXReader saxReader = new SAXReader();

        // 4. Security: Prevent XXE (XML External Entity) attacks
        // Disabling DOCTYPE declarations prevents entity expansion and external entity reference attacks.
        try {
            saxReader.setFeature("http://apache.org/xml/features/disallow-doctype-decl", true);
        } catch (Exception e) {
            // If the underlying parser does not support this feature, fail securely
            throw new Exception("Security configuration error: Unable to disable DOCTYPE in XML parser", e);
        }

        org.dom4j.Document dom4jDocument;

        // 5. Parse XML content
        try {
            dom4jDocument = saxReader.read(file);
        } catch (DocumentException e) {
            // 6. Exception Handling: Handle invalid XML format
            throw new Exception("Failed to parse XML content: Invalid XML format at " + configPath, e);
        }

        // 7. Convert DOM4J Document to W3C Standard Document
        // DOMWriter bridges the gap between DOM4J's internal model and the standard W3C DOM.
        DOMWriter domWriter = new DOMWriter();
        Document w3cDocument = domWriter.write(dom4jDocument);

        return w3cDocument;
    }
}
